package ide.eclipse.bundles.org.apache.syncope.ide.eclipse.plugin.org.apache.syncope.ide.eclipse.plugin.editors.htmlhelpers;

public class InnerJavaScriptScanner extends JavaScriptScanner { public InnerJavaScriptScanner ( ) { super ( ) ; } @ Override protected List < IRule > createRules ( ) { IToken tag = new Token ( new TextAttribute ( new Color ( Display . getCurrent ( ) , IHTMLColorConstants . TAG ) ) ) ; IToken comment = new Token ( new TextAttribute ( new Color ( Display . getCurrent ( ) , IHTMLColorConstants . JAVA_COMMENT ) ) ) ; IToken jsdoc = new Token ( new TextAttribute ( new Color ( Display . getCurrent ( ) , IHTMLColorConstants . JSDOC ) ) ) ; List < IRule > rules = super . createRules ( ) ; rules . add ( new SingleLineRule ( " <script" , ">" , tag ) ) ; rules . add ( new SingleLineRule ( " </script" , ">" , tag ) ) ; rules . add ( new MultiLineRule ( "/**" , "*/" , jsdoc ) ) ; rules . add ( new MultiLineRule ( "/*" , "*/" , comment ) ) ; return rules ; } }